INSERT IGNORE INTO `posts` (`id`, `title`, `content`, `image_url`, `author_id`, `is_pinned`, `view_count`, `created_at`, `updated_at`, `deleted_at`) VALUES
('16f0ec61-4ed9-4881-88ec-0c3054632c2a', 'ม.อุบลฯ รวมใจเชียร์ไทยให้สุดเสียง! ร่วมส่งแรงใจสู้ศึกชิงแชมป์โลก เปตอง 2026', 'ตรียมเสียงเชียร์ให้พร้อม! เพราะชัยชนะครั้งนี้ต้องการกำลังใจจากพวกเราทุกคน 🤝 มหาวิทยาลัยอุบลราชธานีขอเชิญชวนพี่น้องชาว ม.อุบลฯ และชาวไทยทั่วประเทศ ร่วมส่งพลังใจเชียร์ \"ทีมชาติไทย\" ในการแข่งขันเปตองชิงแชมป์โลก\n📍 พบกันที่: ขอนแก่น, ประเทศไทย\n🗓 วันที่: 20 - 25 พฤศจิกายน 2569\nมาร่วมสร้างประวัติศาสตร์และประกาศศักดา \"Thai Spirit Strong Together\" ให้โลกรู้ว่าหัวใจไทยไม่แพ้ใครในโลก!\n#UbonRatchathaniUniversity #UBU #เปตองทีมชาติไทย #PetanqueWorldChampionship2026 #เชียร์ไทยให้สุดใจ #ทีมชาติไทย ', 'https://scontent.fnak4-2.fna.fbcdn.net/v/t39.30808-6/685183884_963440506233989_6177446274087467852_n.jpg?_nc_cat=111&ccb=1-7&_nc_sid=127cfc&_nc_ohc=_StEJu_GaDgQ7kNvwELUZRl&_nc_oc=AdrVHLAHYNJIsoo72GIrFRmyIVaS6QGdSXh7ucCl8sxZnt4qT3ynjRUl9FOUdWIzMCNFzlZOlKAW4J0uaxWjweEn&_nc_zt=23&_nc_ht=scontent.fnak4-2.fna&_nc_gid=kPFkzcUvF4zpahDQUCxQJw&_nc_ss=7b2a8&oh=00_Af4O_AW9pO-ocFB1WDqkbImklems0dZewqAtD3YjEDBYlw&oe=6A0A61AE', 'e3f1e673-571a-4405-aba7-c75cdfc32730', 0, 12, '2026-05-13 15:35:35', '2026-05-13 23:54:13', NULL),
('672a2a3d-3f25-4903-83dc-85082f33a322', 'ชมรมเปตองขอร่วมแสดงความยินดีและความภาคภูมิใจอย่างสุดซึ้ง ❤️🏆', 'โดย อาจารย์ที่ปรึกษาชมรม ที่ได้รับเกียรติและโอกาสอันทรงคุณค่าในการเข้าร่วม หลักสูตรอบรมผู้ตัดสิน ABSC ประจำปี 2025 (ABSC Umpire Course 2025)\nซึ่งเป็นหลักสูตรระดับนานาชาติที่จัดขึ้นควบคู่กับการแข่งขันเปตองชิงแชมป์เอเชีย 2025 ทั้งในประเภทเยาวชน ทีมหญิง และทีมชาย\n📅 ระหว่างวันที่ 3 – 5 พฤศจิกายน 2025 (หลักสูตร 3 วัน)\n📍 ณ Sunway Velocity Hotel ระดับ 4 ดาว\nย่าน Cheras กรุงกัวลาลัมเปอร์ ประเทศมาเลเซีย\nโดยได้รับเกียรติจากวิทยากรผู้ทรงคุณวุฒิระดับโลก\nMr. Alex Chen และ นายแพทย์วินิตย์ จารุพาณิชย์กุล\nผู้ตัดสินระดับสหพันธ์เปตองนานาชาติ (FIPJP)\nซึ่งสะท้อนถึงมาตรฐาน ความเชี่ยวชาญ และความเป็นมืออาชีพในวงการกีฬาเปตองระดับเอเชียและระดับโลก\nการได้รับโอกาสเข้าร่วมการอบรมในครั้งนี้\nนับเป็นความสำเร็จที่น่าภาคภูมิใจอย่างยิ่ง\nและเป็นอีกหนึ่งก้าวสำคัญในการพัฒนาศักยภาพบุคลากรด้านกีฬา\nที่จะนำองค์ความรู้ ประสบการณ์ และมาตรฐานสากล\nกลับมาถ่ายทอดและยกระดับวงการเปตองของสถาบันและประเทศไทยต่อไป 🇹🇭\n✨ ชมรมเปตองขอร่วมชื่นชมในความมุ่งมั่น ทุ่มเท และความเป็นแบบอย่างที่ดีของท่านอาจารย์ที่ปรึกษา ที่พัฒนาตนเองอยู่เสมอและคอยเป็นแรงผลักดันให้ชมรมของเรามีความเข้มแข็งมากขึ้น 🫶🏻💖\n#ชมรมเปตองมออุบล\n#เปตอง\n#เปตองมออู้บู้\n#ชมรมเปตองมหาวิทยาลัยอุบลราชธานี\n#petanque ', 'https://scontent.fnak4-2.fna.fbcdn.net/v/t39.30808-6/675012362_951575370753836_1526427468418321953_n.jpg?_nc_cat=111&ccb=1-7&_nc_sid=833d8c&_nc_ohc=qjmkhRf8aP8Q7kNvwFLgOtq&_nc_oc=Adq3tYDvrQYHRfNp-vjy0E8x4vdmd2Pj2wsYCBsEhN4wh0sxg5qVcDXIaDCGYo3kDl4qnTEC5ImkwgMP-4D8KZC-&_nc_zt=23&_nc_ht=scontent.fnak4-2.fna&_nc_gid=K4LX-oMAnhQZnYEECMnOLA&_nc_ss=7b2a8&oh=00_Af7dq1-8CAdLYN-jNsrtYHsOumhGuVan8fDCyXLn7ar3iA&oe=6A0A791B', 'e3f1e673-571a-4405-aba7-c75cdfc32730', 1, 11, '2026-05-13 15:42:12', '2026-05-18 10:45:12', NULL);
